import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RestController;

import com.fasterxml.jackson.databind.JsonNode;
import org.json.JSONObject;

import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import org.springframework.http.ResponseEntity;
import org.springframework.web.client.RestTemplate;

@RestController
public class WebhookHandler {

    @Autowired
    private RestTemplate restTemplate;

    @PostMapping("/webhooks")
    public ResponseEntity<String> handleWebhook(@RequestBody JsonNode webhookData) {
        try {
            String partnerUrl = getPartnerUrlFromWebhook(webhookData);
            String content = fetchContent(partnerUrl);
            return ResponseEntity.ok(content);
        } catch (Exception e) {
            return ResponseEntity.badRequest().body(e.getMessage());
        }
    }

    private String getPartnerUrlFromWebhook(JsonNode webhookData) {
        // Extract partner URL from webhook data
        JsonNode partnerUrlNode = webhookData.get("partner_url");
        if (partnerUrlNode == null || !partnerUrlNode.isTextual()) {
            throw new RuntimeException("Missing or invalid partner URL in webhook data");
        }
        return partnerUrlNode.asText();
    }

    private String fetchContent(String url) throws Exception {
        HttpClient client = HttpClient.newHttpClient();
        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create(url))
                .GET()
                .build();

        HttpResponse<String> response = client.send(request, HttpResponse.BodyHandlers.ofString());
        return response.body();
    }
}